class Solution:
    def compressedString(self, word):
        result = []
        i = 0
        while i < len(word):
            ch = word[i]
            j = i
            while j < len(word) and word[j] == ch:
                j += 1
            run = j - i
            while run > 0:
                take = min(run, 9)
                result.append(str(take) + ch)
                run -= take
            i = j
        return ''.join(result)

