class Solution:
    def compressedString(self, word):
        comp = []
        i = 0
        n = len(word)
        while i < n:
            ch = word[i]
            count = 0
            while i < n and word[i] == ch and count < 9:
                count += 1
                i += 1
            comp.append(str(count) + ch)
        return ''.join(comp)

