var compressedString = function(word) {
    let comp = '';
    let i = 0;
    const n = word.length;
    while (i < n) {
        const ch = word[i];
        let count = 0;
        while (i < n && word[i] === ch && count < 9) {
            count++;
            i++;
        }
        comp += count + ch;
    }
    return comp;
};
